tokens_db = {"token1", "token2", "token3"}  # You would replace this with your actual DB

def require_oauth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('Authorization', None)
        
        if not auth:
            return jsonify({"code": "authorization_header_missing", 
                            "description": "Authorization header is expected"}), 403
            
        parts = auth.split()
        
        if parts[0].lower() != 'bearer':
            return jsonify({"code": "invalid_request",
                           "description": "Authorization header must start with Bearer"}), 401
        elif len(parts) == 1:
            return jsonify({"code":"invalid_request","description": "Token not found"}), 403
        elif len(parts) > 2:
            return jsonify({"code": "invalid_request", "description": "Authorization header must be 'Bearer token'"}), 401
        
        token = parts[1]
        
        if token not in tokens_db:
            return jsonify({"code":"token_not_found","description":"Invalid Token."}), 403
            
        return f(*args, **kwargs)
    return decorated
    
